     1→import Foundation
     2→
     3→/// Protocol for creature behaviors
     4→public protocol Behavior: Sendable {
     5→    /// The type of this behavior
     6→    var type: BehaviorType { get }
     7→
     8→    /// Required animations for this behavior
     9→    var requiredAnimations: [String] { get }
    10→
    11→    /// Initialize behavior state
    12→    func start(context: BehaviorContext, random: RandomSource) -> BehaviorState
    13→
    14→    /// Update behavior state, returns events generated
    15→    func update(
    16→        state: inout BehaviorState,
    17→        context: BehaviorContext,
    18→        deltaTime: TimeInterval
    19→    ) -> [BehaviorEvent]
    20→
    21→    /// Cancel behavior, transition to exit
    22→    func cancel(state: inout BehaviorState) -> [BehaviorEvent]
    23→}
    24→
    25→// MARK: - Behavior Registry
    26→
    27→/// Registry of available behaviors
    28→public final class BehaviorRegistry: @unchecked Sendable {
    29→    public static let shared = BehaviorRegistry()
    30→
    31→    private var behaviors: [BehaviorType: any Behavior] = [:]
    32→    private let lock = NSLock()
    33→
    34→    private init() {
    35→        // Register default behaviors
    36→        register(PeekBehavior())
    37→        register(TraverseBehavior())
    38→        register(StationaryBehavior())
    39→        register(ClimberBehavior())
    40→        register(FollowBehavior())
    41→    }
    42→
    43→    public func register(_ behavior: any Behavior) {
    44→        lock.lock()
    45→        defer { lock.unlock() }
    46→        behaviors[behavior.type] = behavior
    47→    }
    48→
    49→    public func behavior(for type: BehaviorType) -> (any Behavior)? {
    50→        lock.lock()
    51→        defer { lock.unlock() }
    52→        return behaviors[type]
    53→    }
    54→
    55→    public func allBehaviors() -> [any Behavior] {
    56→        lock.lock()
    57→        defer { lock.unlock() }
    58→        return Array(behaviors.values)
    59→    }
    60→
    61→    public func availableBehaviors(for creature: Creature) -> [any Behavior] {
    62→        allBehaviors().filter { behavior in
    63→            behavior.requiredAnimations.allSatisfy { creature.animations[$0] != nil }
    64→        }
    65→    }
    66→}
    67→

