     1→import Foundation
     2→
     3→/// Schedules creature appearances at random intervals
     4→public final class BehaviorScheduler: @unchecked Sendable {
     5→    public typealias TriggerHandler = (Creature, BehaviorType) -> Void
     6→
     7→    private var settings: Settings
     8→    private var creatures: [Creature]
     9→    private var timeSource: TimeSource
    10→    private var random: RandomSource
    11→    private var onTrigger: TriggerHandler?
    12→
    13→    private var timer: DispatchSourceTimer?
    14→    private var nextTriggerTime: TimeInterval = 0
    15→    private var isRunning = false
    16→    private let lock = NSLock()
    17→
    18→    public init(
    19→        settings: Settings = .default,
    20→        creatures: [Creature] = [],
    21→        timeSource: TimeSource = SystemTimeSource(),
    22→        random: RandomSource = SystemRandomSource()
    23→    ) {
    24→        self.settings = settings
    25→        self.creatures = creatures
    26→        self.timeSource = timeSource
    27→        self.random = random
    28→    }
    29→
    30→    // MARK: - Configuration
    31→
    32→    public func updateSettings(_ settings: Settings) {
    33→        lock.lock()
    34→        defer { lock.unlock() }
    35→        self.settings = settings
    36→    }
    37→
    38→    public func updateCreatures(_ creatures: [Creature]) {
    39→        lock.lock()
    40→        defer { lock.unlock() }
    41→        self.creatures = creatures
    42→    }
    43→
    44→    public func setTriggerHandler(_ handler: @escaping TriggerHandler) {
    45→        lock.lock()
    46→        defer { lock.unlock() }
    47→        self.onTrigger = handler
    48→    }
    49→
    50→    // MARK: - Control
    51→
    52→    public func start() {
    53→        lock.lock()
    54→        defer { lock.unlock() }
    55→
    56→        guard !isRunning else { return }
    57→        isRunning = true
    58→        scheduleNextTrigger()
    59→    }
    60→
    61→    public func stop() {
    62→        lock.lock()
    63→        defer { lock.unlock() }
    64→
    65→        isRunning = false
    66→        timer?.cancel()
    67→        timer = nil
    68→    }
    69→
    70→    public func triggerNow(creature: Creature? = nil, behavior: BehaviorType? = nil) {
    71→        lock.lock()
    72→        let handler = onTrigger
    73→        let selectedCreature = creature ?? selectRandomCreature()
    74→        let selectedBehavior: BehaviorType?
    75→        if let c = selectedCreature {
    76→            selectedBehavior = behavior ?? selectRandomBehavior(for: c)
    77→        } else {
    78→            selectedBehavior = nil
    79→        }
    80→        lock.unlock()
    81→
    82→        guard let c = selectedCreature, let b = selectedBehavior else { return }
    83→        handler?(c, b)
    84→    }
    85→
    86→    // MARK: - Simulation
    87→
    88→    /// Simulate scheduling for testing/preview
    89→    public func simulate(duration: TimeInterval) -> [(time: TimeInterval, creature: String, behavior: BehaviorType)] {
    90→        var results: [(TimeInterval, String, BehaviorType)] = []
    91→        var elapsed: TimeInterval = 0
    92→
    93→        while elapsed < duration {
    94→            let interval = settings.randomInterval(using: random)
    95→            elapsed += interval
    96→
    97→            if elapsed < duration {
    98→                if let creature = selectRandomCreature(),
    99→                   let behavior = selectRandomBehavior(for: creature) {
   100→                    results.append((elapsed, creature.id, behavior))
   101→                }
   102→            }
   103→        }
   104→
   105→        return results
   106→    }
   107→
   108→    // MARK: - Private
   109→
   110→    private func scheduleNextTrigger() {
   111→        guard isRunning else { return }
   112→
   113→        let interval = settings.randomInterval(using: random)
   114→        nextTriggerTime = timeSource.now + interval
   115→
   116→        timer?.cancel()
   117→
   118→        let timer = DispatchSource.makeTimerSource(queue: .main)
   119→        timer.schedule(deadline: .now() + interval)
   120→        timer.setEventHandler { [weak self] in
   121→            self?.handleTrigger()
   122→        }
   123→        self.timer = timer
   124→        timer.resume()
   125→    }
   126→
   127→    private func handleTrigger() {
   128→        lock.lock()
   129→        guard isRunning, settings.enabled else {
   130→            lock.unlock()
   131→            return
   132→        }
   133→
   134→        let handler = onTrigger
   135→        let creature = selectRandomCreature()
   136→        let behavior = creature.flatMap { selectRandomBehavior(for: $0) }
   137→        lock.unlock()
   138→
   139→        if let c = creature, let b = behavior {
   140→            handler?(c, b)
   141→        }
   142→
   143→        lock.lock()
   144→        scheduleNextTrigger()
   145→        lock.unlock()
   146→    }
   147→
   148→    private func selectRandomCreature() -> Creature? {
   149→        var pool = creatures
   150→
   151→        // Filter by enabled creatures if specified
   152→        if !settings.enabledCreatures.isEmpty {
   153→            pool = pool.filter { settings.enabledCreatures.contains($0.id) }
   154→        }
   155→
   156→        guard !pool.isEmpty else { return nil }
   157→
   158→        let index = random.int(in: 0..<pool.count)
   159→        return pool[index]
   160→    }
   161→
   162→    private func selectRandomBehavior(for creature: Creature) -> BehaviorType? {
   163→        let available = BehaviorRegistry.shared.availableBehaviors(for: creature)
   164→        guard !available.isEmpty else { return nil }
   165→
   166→        // Apply behavior weights
   167→        let weighted: [(BehaviorType, Double)] = available.map { behavior in
   168→            let weight = settings.behaviorWeights[behavior.type.rawValue] ?? 1.0
   169→            return (behavior.type, weight)
   170→        }
   171→
   172→        let totalWeight = weighted.reduce(0) { $0 + $1.1 }
   173→        guard totalWeight > 0 else { return available.first?.type }
   174→
   175→        var roll = random.double(in: 0...totalWeight)
   176→        for (type, weight) in weighted {
   177→            roll -= weight
   178→            if roll <= 0 {
   179→                return type
   180→            }
   181→        }
   182→
   183→        return available.first?.type
   184→    }
   185→}
