     3→/// Creature personality affecting behavior timing and patterns
     4→public enum Personality: String, CaseIterable, Codable, Sendable {
     5→    case shy
     6→    case curious
     7→    case mischievous
     8→    case chaotic
     9→
    10→    /// Peek duration range in seconds
    11→    public var peekDurationRange: ClosedRange<Double> {
    12→        switch self {
    13→        case .shy: return 1.5...3.0
    14→        case .curious: return 3.0...6.0
    15→        case .mischievous: return 2.0...5.0
    16→        case .chaotic: return 0.5...8.0
    17→        }
    18→    }
    19→
    20→    /// Retreat speed multiplier (1.0 = normal)
    21→    public var retreatSpeedMultiplier: Double {
    22→        switch self {
    23→        case .shy: return 1.5      // Fast
    24→        case .curious: return 1.0  // Medium
    25→        case .mischievous: return 1.0
    26→        case .chaotic: return Double.random(in: 0.5...2.0) // Variable
    27→        }
    28→    }
    29→
    30→    /// Likelihood to flee from cursor (0-1)
    31→    public var cursorSensitivity: Double {
    32→        switch self {
    33→        case .shy: return 0.9
    34→        case .curious: return 0.3
    35→        case .mischievous: return 0.5
    36→        case .chaotic: return 0.6
    37→        }
    38→    }
    39→}
