    41→/// A creature definition loaded from disk
    42→public struct Creature: Equatable, Codable, Sendable {
    43→    public let id: String
    44→    public let name: String
    45→    public let personality: Personality
    46→    public let animations: [String: Animation]
    47→
    48→    public init(id: String, name: String, personality: Personality, animations: [String: Animation]) {
    49→        self.id = id
    50→        self.name = name
    51→        self.personality = personality
    52→        self.animations = animations
    53→    }
    54→
    55→    /// Get animation by name
    56→    public func animation(named name: String) -> Animation? {
    57→        animations[name]
    58→    }
    59→}
    60→
    61→/// Creature manifest for loading from JSON
    62→public struct CreatureManifest: Codable, Sendable {
    63→    public let id: String
    64→    public let name: String
    65→    public let personality: String
    66→    public let animations: [AnimationEntry]
    67→
    68→    public struct AnimationEntry: Codable, Sendable {
    69→        public let name: String
    70→        public let frameCount: Int
    71→        public let fps: Double?
    72→        public let looping: Bool?
    73→    }
    74→
    75→    public func toCreature() -> Creature? {
    76→        guard let personality = Personality(rawValue: personality) else { return nil }
    77→
    78→        var anims: [String: Animation] = [:]
    79→        for entry in animations {
    80→            anims[entry.name] = Animation(
    81→                name: entry.name,
    82→                frameCount: entry.frameCount,
    83→                fps: entry.fps ?? 12,
    84→                looping: entry.looping ?? false
    85→            )
    86→        }
    87→
    88→        return Creature(id: id, name: name, personality: personality, animations: anims)
    89→    }
    90→}
